function normalizeTeamName(name) {
  const n = String(name || '').trim();
  const compact = n.toLowerCase().replace(/[^a-z0-9]/g, '');
  const aliases = {
    zambogeys: 'Zambogeys',
    bombsaway: 'Bombs Away',
    puttinggoons: 'Putting Goons',
    puttergoons: 'Putting Goons',
    theputtinggoons: 'Putting Goons',
    theputtergoons: 'Putting Goons',
    fairwayenforcers: 'Fairway Enforcers',
    pinsharks: 'Pin Sharks',
    roughriders: 'Rough Riders',
    twococksoneball: '2 Cocks 1 Ball',
    cocksball: '2 Cocks 1 Ball',
    two1ball: '2 Cocks 1 Ball',
    footwedgecrew: 'Foot Wedge Crew'
  };
  return aliases[compact] || n;
}

function formatSheetDate(value) {
  if (!value) return '';
  const d = new Date(value);
  if (isNaN(d.getTime())) return String(value);
  return d.toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    timeZone: 'America/New_York'
  });
}

function parseSheetNumber(value, fallback = 0) {
  const n = Number(value);
  return isNaN(n) ? fallback : n;
}

function buildTeamsFromSheet(data) {
  const playersByTeam = {};

  (data.players || []).forEach(p => {
    if (String(p['Active?'] || p.Active || '').toLowerCase() === 'no') return;
    const team = normalizeTeamName(p.Team);
    if (!team) return;
    if (!playersByTeam[team]) playersByTeam[team] = [];
    if (p['Player Name']) playersByTeam[team].push(p['Player Name']);
  });

  const standingsByTeam = {};
  (data.standings || []).forEach(s => {
    const team = normalizeTeamName(s.Team || s['Display Name'] || s['Short Name']);
    if (team) standingsByTeam[team] = s;
  });

  const sheetTeams = (data.teams && data.teams.length)
    ? data.teams
    : DEFAULT_TEAMS.map(t => ({ 'Display Name': t.name }));

  return sheetTeams
    .filter(t => String(t.Status || 'Active').toLowerCase() !== 'inactive')
    .map(t => {
      const name = normalizeTeamName(t['Display Name'] || t['Short Name'] || t.name);
      const st = standingsByTeam[name] || {};
      const defaultTeam = DEFAULT_TEAMS.find(x => normalizeTeamName(x.name) === name);
      const players = playersByTeam[name] && playersByTeam[name].length
        ? playersByTeam[name].join(' & ')
        : defaultTeam
          ? defaultTeam.players
          : '';

      return {
        name,
        players,
        w: parseSheetNumber(st.W || st.Wins || 0),
        l: parseSheetNumber(st.L || st.Losses || 0),
        holesWon: parseSheetNumber(st.HW || st.HolesWon || 0),
        holesLost: parseSheetNumber(st.HL || st.HolesLost || 0),
        holeDiff: parseSheetNumber(st.HDiff || st['Hole Differential'] || 0),
        matches: parseSheetNumber(st.Matches || 0),
        playoffOpponent: st['Opening Round If Playoffs Started Today'] || ''
      };
    });
}

function buildScheduleFromSheet(data) {
  const byWeek = {};

  (data.schedule || []).forEach(row => {
    const week = Number(row.Week || row.week || 0);
    if (!week) return;

    if (!byWeek[week]) {
      byWeek[week] = {
        week,
        date: formatSheetDate(row.Date),
        side: row.Side || '',
        status: '',
        matchups: []
      };
    }
    if (['completed','complete'].includes(String(row.Status || '').trim().toLowerCase())) {
      byWeek[week].status = 'completed';
    }

    const home = normalizeTeamName(row['Team 1'] || row.Team1 || row.home || '');
    const away = normalizeTeamName(row['Team 2'] || row.Team2 || row.away || '');

    byWeek[week].matchups.push({
      time: row['Tee Time'] || row.TeeTime || '',
      home: home || 'TBD',
      away: away || 'TBD',
      status: row.Status || '',
      matchId: row.MatchID || ''
    });
  });

  return Object.values(byWeek).sort((a, b) => a.week - b.week);
}

function parseLeagueJsonValue(value) {
  if (!value) return null;
  if (typeof value === 'object') return value;
  if (typeof value !== 'string') return null;
  const trimmed = value.trim();
  if (!trimmed || trimmed === '[object Object]') return null;
  try {
    return JSON.parse(trimmed);
  } catch (e) {
    return null;
  }
}


function getRowValue(row, keys) {
  if (!row) return '';
  for (const key of keys) {
    if (row[key] !== undefined && row[key] !== null && row[key] !== '') return row[key];
  }
  const wanted = keys.map(k => String(k).toLowerCase().replace(/[^a-z0-9]/g, ''));
  for (const actualKey of Object.keys(row)) {
    const compact = String(actualKey).toLowerCase().replace(/[^a-z0-9]/g, '');
    if (wanted.includes(compact) && row[actualKey] !== undefined && row[actualKey] !== null && row[actualKey] !== '') return row[actualKey];
  }
  return '';
}

function normalizeSnapshotPlayer(raw, index, row) {
  raw = raw || {};
  row = row || {};
  const fallbackIds = ['p1a', 'p1b', 'p2a', 'p2b'];
  const playerNo = index + 1;
  const team1 = normalizeTeamName(getRowValue(row, ['Team1', 'Team 1', 'team1']));
  const team2 = normalizeTeamName(getRowValue(row, ['Team2', 'Team 2', 'team2']));
  const sideTeam = index < 2 ? team1 : team2;
  return {
    id: raw.id || raw.playerId || raw.key || fallbackIds[index],
    playerId: raw.playerId || raw.id || fallbackIds[index],
    name: normalizePlayerStatName(raw.name || raw.Name || raw['Player Name'] || raw.player || raw.Player || getRowValue(row, [
      'P' + playerNo + 'Name', 'P' + playerNo + ' Name', 'Player' + playerNo + 'Name', 'Player ' + playerNo + ' Name', 'Player ' + playerNo
    ])),
    ghin: raw.ghin || raw.GHIN || raw.index || raw.Index || getRowValue(row, [
      'P' + playerNo + 'GHIN', 'P' + playerNo + ' GHIN', 'Player' + playerNo + 'GHIN', 'Player ' + playerNo + ' GHIN', 'Player ' + playerNo + ' Index'
    ]),
    team: normalizeTeamName(raw.team || raw.Team || getRowValue(row, [
      'P' + playerNo + 'Team', 'P' + playerNo + ' Team', 'Player' + playerNo + 'Team', 'Player ' + playerNo + ' Team'
    ]) || sideTeam)
  };
}

function buildPlayersSnapshotFromRow(row) {
  const fallbackIds = ['p1a', 'p1b', 'p2a', 'p2b'];
  const players = [];
  for (let i = 0; i < 4; i++) {
    const playerNo = i + 1;
    const name = getRowValue(row, [
      'P' + playerNo + 'Name', 'P' + playerNo + ' Name', 'Player' + playerNo + 'Name', 'Player ' + playerNo + ' Name', 'Player ' + playerNo
    ]);
    const ghin = getRowValue(row, [
      'P' + playerNo + 'GHIN', 'P' + playerNo + ' GHIN', 'Player' + playerNo + 'GHIN', 'Player ' + playerNo + ' GHIN', 'Player ' + playerNo + ' Index'
    ]);
    if (name || ghin) players.push(normalizeSnapshotPlayer({ id: fallbackIds[i], name, ghin }, i, row));
  }
  if (players.length >= 4) return players;

  const playerLine = getRowValue(row, ['PlayerLine', 'Player Line', 'playerLine']);
  const parsed = parsePlayerLinePlayers(playerLine);
  if (parsed.some(Boolean)) {
    return parsed.map(function(name, i) {
      return normalizeSnapshotPlayer({ id: fallbackIds[i], name: name || ('Player ' + (i + 1)) }, i, row);
    });
  }
  return [];
}

function getFlatScoreValue(row, playerNo, holeNo) {
  return getRowValue(row, [
    'P' + playerNo + 'H' + holeNo,
    'P' + playerNo + ' H' + holeNo,
    'P' + playerNo + '_H' + holeNo,
    'P' + playerNo + 'Hole' + holeNo,
    'P' + playerNo + ' Hole ' + holeNo,
    'P' + playerNo + 'Gross' + holeNo,
    'P' + playerNo + ' Gross ' + holeNo,
    'Player' + playerNo + 'H' + holeNo,
    'Player' + playerNo + 'Hole' + holeNo,
    'Player ' + playerNo + ' H' + holeNo,
    'Player ' + playerNo + ' Hole ' + holeNo,
    'Player ' + playerNo + ' Gross ' + holeNo
  ]);
}

function buildScoreSnapshotFromFlatColumns(row, playersSnapshot) {
  const fallbackIds = ['p1a', 'p1b', 'p2a', 'p2b'];
  const snapshot = {};
  for (let i = 0; i < 4; i++) {
    const playerNo = i + 1;
    const id = (playersSnapshot[i] && (playersSnapshot[i].id || playersSnapshot[i].playerId)) || fallbackIds[i];
    for (let holeNo = 1; holeNo <= 18; holeNo++) {
      const raw = getFlatScoreValue(row, playerNo, holeNo);
      const n = parseInt(raw, 10);
      if (Number.isFinite(n) && n > 0) {
        snapshot[id + '_' + holeNo] = n;
        snapshot[fallbackIds[i] + '_' + holeNo] = n;
      }
    }
  }
  return snapshot;
}

function ensureSnapshotPlayerIds(playersSnapshot) {
  const fallbackIds = ['p1a', 'p1b', 'p2a', 'p2b'];
  return (playersSnapshot || []).slice(0, 4).map(function(p, i) {
    return normalizeSnapshotPlayer({ ...p, id: p.id || p.playerId || fallbackIds[i] }, i, {});
  });
}

function normalizeScorePayload(row) {
  const rawScores =
    row.PlayerScoresJSON ||
    row['Player Scores JSON'] ||
    row['Score Snapshot JSON'] ||
    row.ScoreSnapshotJSON ||
    row['Score Snapshot Only JSON'] ||
    row.ScoreSnapshotOnlyJSON ||
    row.ScoreJSON ||
    row.ScoresJSON ||
    row['Scores JSON'] ||
    row.playerScores ||
    row.PlayerScores ||
    '';

  const parsed = parseLeagueJsonValue(rawScores) || {};
  const nested = parsed.playerScores || parsed.PlayerScores || parsed.data || parsed;

  let playersSnapshot =
    nested.playersSnapshot ||
    nested.PlayersSnapshot ||
    nested.players ||
    row.playersSnapshot ||
    parseLeagueJsonValue(row.PlayersSnapshotJSON || row['Players Snapshot JSON'] || '') ||
    [];

  playersSnapshot = parseLeagueJsonValue(playersSnapshot) || playersSnapshot || [];
  if (!Array.isArray(playersSnapshot) || playersSnapshot.length < 4) {
    playersSnapshot = buildPlayersSnapshotFromRow(row);
  } else {
    playersSnapshot = playersSnapshot.map(function(p, i) { return normalizeSnapshotPlayer(p || {}, i, row); });
  }
  playersSnapshot = ensureSnapshotPlayerIds(playersSnapshot);

  let scoreSnapshot =
    nested.scoreSnapshot ||
    nested.ScoreSnapshot ||
    nested.scorecardScores ||
    nested.scores ||
    row.scoreSnapshot ||
    parseLeagueJsonValue(row.ScoreSnapshot || row['Score Snapshot'] || row['Score Snapshot Only JSON'] || row.ScoreSnapshotOnlyJSON || '') ||
    {};

  scoreSnapshot = parseLeagueJsonValue(scoreSnapshot) || scoreSnapshot || {};
  if (!scoreSnapshot || typeof scoreSnapshot !== 'object' || Array.isArray(scoreSnapshot)) scoreSnapshot = {};

  const flatSnapshot = buildScoreSnapshotFromFlatColumns(row, playersSnapshot);
  if (!Object.keys(scoreSnapshot).length || Object.keys(flatSnapshot).length > Object.keys(scoreSnapshot).length) {
    scoreSnapshot = { ...scoreSnapshot, ...flatSnapshot };
  }

  return { playersSnapshot, scoreSnapshot };
}


function normalizeResultFromSheet(row) {
  const scorePayload = normalizeScorePayload(row);
  const playersSnapshot = scorePayload.playersSnapshot;
  const scoreSnapshot = scorePayload.scoreSnapshot;

  let playerLine = row.PlayerLine || row['Player Line'] || row.playerLine || '';
  if (!playerLine && Array.isArray(playersSnapshot) && playersSnapshot.length >= 4) {
    playerLine = `${playersSnapshot[0].name || playersSnapshot[0]['Player Name'] || 'Player A'} & ${playersSnapshot[1].name || playersSnapshot[1]['Player Name'] || 'Player B'} vs ${playersSnapshot[2].name || playersSnapshot[2]['Player Name'] || 'Player C'} & ${playersSnapshot[3].name || playersSnapshot[3]['Player Name'] || 'Player D'}`;
  }

  return {
    resultId: row.ResultID || row.resultId || '',
    matchId: row.MatchID || row.matchId || '',
    week: Number(row.Week || row.week || 0),
    date: row.Date || row.date || row.SubmittedAt || row['Entered At'] || '',
    side: row.Side || row.side || '',
    team1: normalizeTeamName(row.Team1 || row['Team 1'] || row.team1 || ''),
    team2: normalizeTeamName(row.Team2 || row['Team 2'] || row.team2 || ''),
    winner: normalizeTeamName(row.Winner || row.winner || ''),
    matchResult: row.MatchResult || row['Result Text'] || row.matchResult || '',
    tiebreakerDetail: row.TiebreakerDetail || row.tiebreakerDetail || '',
    team1HolesWon: parseSheetNumber(row.Team1HolesWon || row['Team 1 Holes Won'] || row.team1HolesWon || 0),
    team2HolesWon: parseSheetNumber(row.Team2HolesWon || row['Team 2 Holes Won'] || row.team2HolesWon || 0),
    playerLine,
    holesPlayed: Number(row.HolesPlayed || row['Holes Played'] || row.holesPlayed || 0),
    playersSnapshot,
    scoreSnapshot
  };
}


function applyLeagueDataFromSheet(data) {
  LEAGUE_API_DATA = data;
  TEAMS = buildTeamsFromSheet(data);

  if (data.schedule && data.schedule.length) {
    SCHEDULE_WEEKS = buildScheduleFromSheet(data);
  }

  RESULTS = (data.results || [])
    .map(normalizeResultFromSheet)
    .filter(r => r.week && r.team1 && r.team2);

  if (data.commissionerNote !== undefined && data.commissionerNote !== null) {
    localStorage.setItem('hggl2026_commissioner_note', String(data.commissionerNote));
  }

  if (typeof applySkinsCtpFromSheet === 'function') applySkinsCtpFromSheet(data);
  LEAGUE_DATA_SOURCE = 'Google Sheets';
  LEAGUE_DATA_LAST_LOADED = new Date().toLocaleString('en-US', { timeZone: 'America/New_York' });
}

async function leagueJsonpRequest(action, payload = {}) {
  if (!LEAGUE_API_URL) throw new Error('Missing Google Sheets API URL.');
  const params = new URLSearchParams();
  params.set('action', action);
  params.set('v', String(Date.now()));
  if (payload && Object.keys(payload).length) params.set('payload', JSON.stringify(payload));
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 25000);
  try {
    const response = await fetch(LEAGUE_API_URL + '?' + params.toString(), { method: 'GET', signal: controller.signal });
    clearTimeout(timer);
    if (!response.ok) throw new Error('HTTP ' + response.status);
    const json = await response.json();
    if (!json || json.ok === false) throw new Error((json && json.error) || 'API error');
    return json;
  } catch (err) {
    clearTimeout(timer);
    if (err.name === 'AbortError') throw new Error('Request timed out.');
    throw err;
  }
}

async function fetchLeagueDataFromSheets(silent = false) {
  if (!USE_GOOGLE_SHEETS_SYNC || !LEAGUE_API_URL) return false;

  try {
    const json = await leagueJsonpRequest('getLeagueData');
    applyLeagueDataFromSheet(json.data || {});
    rebuildAll();

    if (typeof initCommissionerNoteEditor === 'function') {
      initCommissionerNoteEditor();
    }

    return true;
  } catch (err) {
    console.warn('Google Sheets sync failed; using local fallback.', err);
    LEAGUE_DATA_SOURCE = 'local fallback';

    if (!silent) {
      alert('Could not load Google Sheets data. The site is using the local backup for now.');
    }

    return false;
  }
}

