    const logo = LOGOS[t.name] ? `<img src="${LOGOS[t.name]}" class="t-logo-sm" alt="${t.name}">` : '';
    return `<span class="ticker-item">${logo} ${t.name} <span class="record">${t.w}-${t.l}</span></span>`;
