var _lrTimer = null;
var _lrIndex = 0;
function getLatestResultsInfo() {
  if (!RESULTS.length) return { week: null, results: [] };
  const weeks = RESULTS.map(function(r){ return parseInt(r.week, 10) || 0; }).filter(Boolean);
  if (!weeks.length) return { week: null, results: [] };
  const latestWeek = Math.max.apply(null, weeks);
  const results = RESULTS.filter(function(r){ return parseInt(r.week, 10) === latestWeek; });
  return { week: latestWeek, results: results };
}

function renderLatestResultsStrip(results, activeIndex) {
  return results.map(function(r, i){
    const winnerName = r.winner || '';
    const shortScore = escapeLeagueHtml(r.matchResult || 'Final');
    const label = escapeLeagueHtml((r.team1 || '') + ' vs ' + (r.team2 || ''));
    return '<button class="latest-result-chip' + (i === activeIndex ? ' active' : '') + '" onclick="jumpLr(' + i + ')">' +
      '<span class="latest-chip-score">' + shortScore + '</span>' +
      '<span class="latest-chip-teams">' + label + '</span>' +
      (winnerName ? '<span class="latest-chip-winner">Winner: ' + escapeLeagueHtml(winnerName) + '</span>' : '') +
    '</button>';
  }).join('');
}

function renderLatestPlayerTotals(result) {
  const totals = getResultPlayerTotals(result).filter(function(p){ return p.hasScores; });
  if (!totals.length) return '';
  return '<div class="latest-player-totals">' + totals.map(function(p){
    return '<span><b>' + escapeLeagueHtml(p.name) + '</b> ' + p.gross + ' gross / ' + p.net + ' net</span>';
  }).join('') + '</div>';
}

function showLatestResult(results, index) {
  if (!results.length) return;
  _lrIndex = ((index % results.length) + results.length) % results.length;
  const r = results[_lrIndex];
  const score = document.getElementById('lr-score');
  const teams = document.getElementById('lr-teams');
  const totals = document.getElementById('lr-player-totals');
  const strip = document.getElementById('lr-scroll');
  const dots = document.getElementById('lr-dots');
  if(score) score.textContent = r.matchResult || 'Final';
  if(teams) teams.textContent = (r.team1 || '') + ' vs ' + (r.team2 || '');
  if(totals) totals.innerHTML = renderLatestPlayerTotals(r);
  if(strip) strip.innerHTML = renderLatestResultsStrip(results, _lrIndex);
  if(dots) dots.querySelectorAll('.lr-dot').forEach(function(d,di){ d.classList.toggle('active',di===_lrIndex); });
}

function initLatestResultCarousel() {
  clearInterval(_lrTimer);
  const info = getLatestResultsInfo();
  const results = info.results;
  const dotsEl = document.getElementById('lr-dots');
  if (!results.length || !dotsEl) return;
  dotsEl.innerHTML = results.map(function(_,i){
    return '<span class="lr-dot'+(i===0?' active':'')+'" onclick="jumpLr('+i+')"></span>';
  }).join('');
  showLatestResult(results, 0);
  if (results.length <= 1) return;
  _lrTimer = setInterval(function(){ showLatestResult(results, _lrIndex + 1); }, 3500);
}

function jumpLr(i) {
  clearInterval(_lrTimer);
  const info = getLatestResultsInfo();
  const results = info.results;
  showLatestResult(results, i);
  if (results.length > 1) {
    _lrTimer = setInterval(function(){ showLatestResult(results, _lrIndex + 1); }, 3500);
  }
}

function getSortedStandings() {
  return [...TEAMS].sort((a,b)=>
    (b.w - a.w) ||
    (a.l - b.l) ||
    ((b.holesWon || 0) - (a.holesWon || 0)) ||
    a.name.localeCompare(b.name)
  );
}

// ── PLAYOFF MATCHUPS ──
function buildPlayoffPicture() {
  const container = document.getElementById('playoff-picture-container');
  if(!container) return;
  const sorted = getSortedStandings();
  const pairings = [[0,7],[1,6],[2,5],[3,4]];
  container.innerHTML = pairings.map(([hi, lo])=>{
    const highSeed = sorted[hi];
    const lowSeed = sorted[lo];
    if(!highSeed || !lowSeed) return '';
    return `<div class="playoff-matchup-row">
      <div class="playoff-team playoff-team-high">
        <div class="playoff-seed">${hi+1}</div>
        ${logoImg(highSeed.name,'mini-logo','m-placeholder')}
        <div><span>${highSeed.name}</span><div class="playoff-record">${highSeed.w}-${highSeed.l} · ${highSeed.holesWon || 0} HW</div></div>
      </div>
      <div class="playoff-vs">VS</div>
      <div class="playoff-team playoff-team-low">
        <div class="playoff-seed">${lo+1}</div>
        ${logoImg(lowSeed.name,'mini-logo','m-placeholder')}
        <div><span>${lowSeed.name}</span><div class="playoff-record">${lowSeed.w}-${lowSeed.l} · ${lowSeed.holesWon || 0} HW</div></div>
      </div>
    </div>`;
  }).join('');
}

function escapeLeagueHtml(value) {
  return String(value || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

function scheduledMatchKey(week, teamA, teamB) {
  const teams = [normalizeTeamName(teamA), normalizeTeamName(teamB)]
    .map(function(t){ return String(t || '').trim().toLowerCase(); })
    .filter(Boolean)
    .sort();
  return String(parseInt(week, 10) || week) + '|' + teams.join('|');
}

function getCompletedScheduleMatchKeys() {
  const keys = new Set();
  RESULTS.forEach(function(r){
    if (!r || !r.week || !r.team1 || !r.team2) return;
    keys.add(scheduledMatchKey(r.week, r.team1, r.team2));
  });
  return keys;
}

function isScheduledMatchCompleted(week, matchup) {
  return getCompletedScheduleMatchKeys().has(scheduledMatchKey(week, matchup.home, matchup.away));
}

function getWeekCompletionInfo(weekObj) {
  const keys = getCompletedScheduleMatchKeys();
  const total = weekObj && weekObj.matchups ? weekObj.matchups.length : 0;
  const completed = weekObj && weekObj.matchups ? weekObj.matchups.filter(function(m){ return keys.has(scheduledMatchKey(weekObj.week, m.home, m.away)); }).length : 0;
  return { total: total, completed: completed, isComplete: total > 0 && completed >= total };
}

function getNextIncompleteWeek() {
  return SCHEDULE_WEEKS.find(function(w){ return !getWeekCompletionInfo(w).isComplete; }) || null;
}

function getResultSnapshotPlayers(r) {
  var snap = Array.isArray(r.playersSnapshot) ? r.playersSnapshot : [];
  if (snap.length >= 4) return snap.slice(0, 4).map(function(p, i){ return normalizeSnapshotPlayer(p, i, { Team1:r.team1, Team2:r.team2 }); });
  const parsedNames = parsePlayerLinePlayers(r.playerLine);
  return parsedNames.map(function(name, i) {
    return normalizeSnapshotPlayer({ id:['p1a','p1b','p2a','p2b'][i], name:name || ('Player ' + (i + 1)), team:i < 2 ? r.team1 : r.team2 }, i, { Team1:r.team1, Team2:r.team2 });
  });
}

function getResultPlayerTotals(r) {
  const snap = getResultSnapshotPlayers(r);
  const scores = r.scoreSnapshot || {};
  if (!Object.keys(scores).length || snap.length < 4) return [];
  const side = r.side === 'Front 9' ? 'front' : 'back';
  const holes = side === 'front' ? COURSE.front : COURSE.back;
  const strokes = calcPlayerStrokes(snap, side);
  const strokeSets = snap.map(function(p, i) { return getStrokeHoles(strokes[i], holes); });
  return snap.map(function(p, pi) {
    let gross = 0, net = 0, holeCount = 0;
    holes.forEach(function(h) {
      const g = getScoreForPlayerHole(scores, p, pi, h.hole);
      if (g === null || isNaN(g)) return;
      gross += g;
      net += g - (strokeSets[pi].has(h.hole) ? 1 : 0);
      holeCount++;
    });
    return {
      name: p.name || ('Player ' + (pi + 1)),
      team: p.team || (pi < 2 ? r.team1 : r.team2),
      gross: holeCount ? gross : '—',
      net: holeCount ? net : '—',
      holes: holeCount,
      hasScores: holeCount > 0
    };
  });
}

function renderPlayerScoreSummary(result) {
  const totals = getResultPlayerTotals(result).filter(function(p){ return p.hasScores; });
  if (!totals.length) return '';
  const team1 = totals.filter(function(p, i){ return i < 2; });
  const team2 = totals.filter(function(p, i){ return i >= 2; });
  function sideHtml(players) {
    return players.map(function(p){
      return '<div class="player-score-pill"><span class="player-score-name">' + escapeLeagueHtml(p.name) + '</span><span class="player-score-values">Gross ' + p.gross + ' · Net ' + p.net + '</span></div>';
    }).join('');
  }
  return '<div class="player-score-summary"><div>' + sideHtml(team1) + '</div><div>' + sideHtml(team2) + '</div></div>';
}


// ── RESULTS ──
function buildResults() {
  const container = document.getElementById('results-container');
  if(!RESULTS.length) {
    container.innerHTML = `<div class="no-results"><div class="no-results-icon">🏌️</div><div class="no-results-text">No results yet<br>Check back after Week 1</div></div>`;
    return;
  }
  const byWeek = {};
  RESULTS.forEach(function(r){ if(!byWeek[r.week]) byWeek[r.week]=[]; byWeek[r.week].push(r); });
  const sortedWeeks = Object.keys(byWeek).sort(function(a,b){return Number(b)-Number(a);});
  container.innerHTML = sortedWeeks.map(function(week) {
    const weekData = byWeek[week];
    const weekInfo = SCHEDULE_WEEKS.find(function(w){ return String(w.week)===String(week); });
    const weekDate = weekInfo ? weekInfo.date : '';
    const weekSide = weekInfo ? weekInfo.side : '';
    const completion = weekInfo ? getWeekCompletionInfo(weekInfo) : { completed: weekData.length, total: weekData.length, isComplete: true };
    const shouldOpen = !completion.isComplete;
    const summaryScores = weekData.map(function(r){
      const t1w = r.winner === r.team1;
      const t2w = r.winner === r.team2;
      return (t1w?'<strong>':'')+escapeLeagueHtml(r.team1)+(t1w?'</strong>':'')+' '+escapeLeagueHtml(r.matchResult)+' '+(t2w?'<strong>':'')+escapeLeagueHtml(r.team2)+(t2w?'</strong>':'');
    }).join(' &nbsp;|&nbsp; ');
    const cards = weekData.map(function(r){
      const t1w = r.winner === r.team1;
      const t2w = r.winner === r.team2;
      const playerSummary = renderPlayerScoreSummary(r);
      return '<div class="result-card">' +
        '<div class="result-teams">' +
        '<div class="result-team">' + logoImg(r.team1,'result-logo','result-placeholder') +
        '<span class="result-name'+(t1w?' winner':'')+'">'+escapeLeagueHtml(r.team1)+'</span></div>' +
        '<div class="result-score-block"><div class="result-matchplay">'+escapeLeagueHtml(r.matchResult)+'</div><div class="result-side">'+escapeLeagueHtml(r.side)+'</div></div>' +
        '<div class="result-team right"><span class="result-name'+(t2w?' winner':'')+'">'+escapeLeagueHtml(r.team2)+'</span>' +
        logoImg(r.team2,'result-logo','result-placeholder')+'</div></div>' +
        '<div class="result-detail">'+escapeLeagueHtml(r.playerLine)+'</div>' +
        playerSummary +
      '<div style="text-align:right;padding:4px 0 2px;">' +
      (function(){ var scId = escapeLeagueHtml(String(r.resultId || ('w'+r.week+'_'+r.team1+'_'+r.team2)).replace(/[^a-zA-Z0-9_-]/g,'')); return '<button onclick="toggleScorecard(this,\''+scId+'\')" ' +
      'style="background:transparent;border:1px solid rgba(216,179,93,0.4);color:var(--gold);' +
      'font-family:\'Barlow Condensed\',sans-serif;font-size:11px;letter-spacing:1px;' +
      'padding:4px 10px;border-radius:999px;cursor:pointer;">▼ View Full Scorecard</button>' +
      '<div id="sc-'+scId+'" style="display:none;margin-top:6px;">'+buildScorecardHTML(r)+'</div>'; })() +
      '</div></div>';
    }).join('');
    const headerLabel = 'Week '+week+(weekDate?' · '+weekDate:'')+(weekSide?' · '+weekSide:'');
    const completionLabel = completion.total ? (completion.completed + '/' + completion.total + ' matches posted') : (weekData.length + ' result' + (weekData.length === 1 ? '' : 's'));
    return '<div class="results-week">' +
      '<div class="results-week-toggle'+(shouldOpen?' open':'')+'" onclick="toggleResultsWeek(this)">' +
      '<div class="results-week-header-row">' +
      '<span class="results-week-title">'+headerLabel+'</span>' +
      '<span class="results-week-status">'+(completion.isComplete?'Completed':'In Progress')+' · '+completionLabel+'</span>' +
      '<span class="results-week-chevron">'+(shouldOpen?'▲':'▼')+'</span></div>' +
      '<div class="results-week-summary">'+summaryScores+'</div></div>' +
      '<div class="results-week-body" style="display:'+(shouldOpen?'block':'none')+'">'+cards+'</div>' +
      '</div>';
  }).join('');
}

function toggleResultsWeek(header) {
  var body = header.nextElementSibling;
  var chevron = header.querySelector('.results-week-chevron');
  var isOpen = body.style.display !== 'none';
  body.style.display = isOpen ? 'none' : 'block';
  chevron.textContent = isOpen ? '▼' : '▲';
  header.classList.toggle('open', !isOpen);
}

// ── SCHEDULE ──
function buildSchedule() {
  const el = document.getElementById('schedule-container');
  const upcoming = SCHEDULE_WEEKS.filter(function(w){ return !getWeekCompletionInfo(w).isComplete; });
  if (!upcoming.length) {
    el.innerHTML = '<div class="no-results"><div class="no-results-icon">🏌‍♂️</div><div class="no-results-text">Season schedule complete.<br>See Results for all match outcomes.</div></div>';
    return;
  }
  el.innerHTML = upcoming.map(function(w){
    const completion = getWeekCompletionInfo(w);
    return '<div class="week-block">' +
    '<div class="week-label">Week ' + w.week + ' &nbsp;·&nbsp; ' + w.date + ' &nbsp;·&nbsp; ' + w.side + ' &nbsp;·&nbsp; ' + completion.completed + '/' + completion.total + ' completed</div>' +
    w.matchups.map(function(m){
      const done = isScheduledMatchCompleted(w.week, m);
      return '<div class="matchup-card'+(done?' completed-match':'')+'">' +
      '<span class="m-time">' + m.time + '</span>' +
      '<div class="m-team right"><span class="m-name">' + m.home + '</span>' + logoImg(m.home,'m-logo','m-placeholder') + '</div>' +
      '<div class="vs-badge">' + (done ? 'FINAL' : 'VS') + '</div>' +
      '<div class="m-team">' + logoImg(m.away,'m-logo','m-placeholder') + '<span class="m-name">' + m.away + '</span></div>' +
      '</div>'; }).join('') +
    '</div>'; }).join('');
}


// ── ADMIN HELPERS ──
function sideValueFromLabel(label) {
  return String(label || '').toLowerCase().includes('back') ? 'back' : 'front';
}

function buildScheduledMatchSelect() {
  const sel = document.getElementById('sc-scheduled-match');
  if(!sel) return;
  const options = ['<option value="">Manual Entry / Select Match</option>'];
  SCHEDULE_WEEKS.forEach(w => {
    w.matchups.forEach((m, idx) => {
      options.push(`<option value="${w.week}|${idx}">Week ${w.week} · ${m.time} · ${m.home} vs ${m.away}</option>`);
    });
  });
  sel.innerHTML = options.join('');
}

function applyScheduledMatch() {
  const sel = document.getElementById('sc-scheduled-match');
  if(!sel || !sel.value) return;
  const [weekVal, matchIndexVal] = sel.value.split('|');
  const week = SCHEDULE_WEEKS.find(w => String(w.week) === String(weekVal));
  if(!week) return;
  const matchup = week.matchups[parseInt(matchIndexVal, 10)];
  if(!matchup) return;
  document.getElementById('sc-week').value = week.week;
  document.getElementById('sc-side').value = sideValueFromLabel(week.side);
  document.getElementById('sc-team1').value = matchup.home;
  document.getElementById('sc-team2').value = matchup.away;
  renderScorecard();
}

function getRosterNames() {
  const names = new Set();
  DEFAULT_TEAMS.forEach(t => String(t.players || '').split('&').forEach(n => {
    const cleaned = n.trim();
    if(cleaned) names.add(cleaned);
  }));
  RESULTS.forEach(r => String(r.playerLine || '').replace(' vs ', ' & ').split('&').forEach(n => {
    const cleaned = n.trim();
    if(cleaned && !cleaned.startsWith('Player')) names.add(cleaned);
  }));
  return [...names].sort((a,b)=>a.localeCompare(b));
}

function buildRosterDatalist() {
  const dl = document.getElementById('roster-options');
  if(!dl) return;
  dl.innerHTML = getRosterNames().map(n => `<option value="${n}"></option>`).join('');
}

function recalcRecordsFromResults() {
  TEAMS = DEFAULT_TEAMS.map(t => ({...t, w:0, l:0, holesWon:0, holesLost:0}));
  RESULTS.forEach(r => {
    const t1 = TEAMS.find(t => t.name === r.team1);
    const t2 = TEAMS.find(t => t.name === r.team2);
    if(!t1 || !t2) return;

    const t1Holes = Number(r.team1HolesWon || r.holesWon?.team1 || 0);
    const t2Holes = Number(r.team2HolesWon || r.holesWon?.team2 || 0);
    t1.holesWon += t1Holes;
    t1.holesLost += t2Holes;
    t2.holesWon += t2Holes;
    t2.holesLost += t1Holes;

    if(r.winner === r.team1) { t1.w++; t2.l++; }
    else if(r.winner === r.team2) { t2.w++; t1.l++; }
    else { t1.w += 0.5; t2.w += 0.5; }
  });
}

function buildResultManager() {
  const sel = document.getElementById('edit-result-select');
  if(!sel) return;
  if(!RESULTS.length) {
    sel.innerHTML = '<option value="">No saved results yet</option>';
    return;
  }
  sel.innerHTML = '<option value="">Select saved result</option>' + RESULTS.map((r,i)=>`<option value="${i}">Week ${r.week} · ${r.team1} vs ${r.team2} · ${r.matchResult}</option>`).join('');
}

function removeResultAt(index) {
  const i = parseInt(index, 10);
  if(isNaN(i) || !RESULTS[i]) { alert('Please select a saved result first.'); return; }
  const r = RESULTS[i];
  if(!confirm(`Remove Week ${r.week}: ${r.team1} vs ${r.team2}?`)) return;
  RESULTS.splice(i, 1);
  recalcRecordsFromResults();
  persistState();
  rebuildAll();
  buildResultManager();
  alert('Result removed.');
}

function deleteSelectedResult() {
  const sel = document.getElementById('edit-result-select');
  if(!sel) return;
  removeResultAt(sel.value);
}

function loadSelectedResultForEdit() {
  const sel = document.getElementById('edit-result-select');
  if(!sel || sel.value === '') { alert('Please select a saved result first.'); return; }
  const i = parseInt(sel.value, 10);
  const r = RESULTS[i];
  if(!r) return;
  if(!confirm('This will load the selected result into the scorecard and remove the saved copy. Re-save after making edits. Continue?')) return;
  RESULTS.splice(i, 1);
  recalcRecordsFromResults();
  persistState();
  document.getElementById('sc-week').value = r.week;
  document.getElementById('sc-side').value = sideValueFromLabel(r.side);
  document.getElementById('sc-team1').value = r.team1;
  document.getElementById('sc-team2').value = r.team2;
  const players = r.playersSnapshot || [];
  ['p1a','p1b','p2a','p2b'].forEach((id, idx) => {
    document.getElementById(id+'-name').value = players[idx]?.name || '';
    document.getElementById(id+'-ghin').value = players[idx]?.ghin || '';
  });
  scorecardScores = {...(r.scoreSnapshot || {})};
  rebuildAll();
  buildResultManager();
  const scoreTabBtn = document.querySelector('.comm-tab[onclick*="scorecard-tab"]');
  if(scoreTabBtn) showCommTab('scorecard-tab', scoreTabBtn);
  renderScorecard();
  alert('Result loaded. Make your changes and save it again.');
}

// ── SCORECARD CORE ──
function getPlayers() {
  return [
    {id:'p1a', name:document.getElementById('p1a-name').value||'Player 1A', ghin:document.getElementById('p1a-ghin').value, team:1},
    {id:'p1b', name:document.getElementById('p1b-name').value||'Player 1B', ghin:document.getElementById('p1b-ghin').value, team:1},
    {id:'p2a', name:document.getElementById('p2a-name').value||'Player 2A', ghin:document.getElementById('p2a-ghin').value, team:2},
    {id:'p2b', name:document.getElementById('p2b-name').value||'Player 2B', ghin:document.getElementById('p2b-ghin').value, team:2},
  ];
}

function getHoles() {
  return document.getElementById('sc-side').value === 'front' ? COURSE.front : COURSE.back;
}

function getPlayerGross(player, hole) {
  const key = `${player.id}_${hole.hole}`;
  const raw = scorecardScores[key];
  if (raw === undefined || raw === null || raw === '') return null;
  const parsed = parseInt(raw, 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
}

function getPlayerNet(player, strokeSet, hole) {
  const gross = getPlayerGross(player, hole);
  if (gross === null) return null;
  return gross - (strokeSet.has(hole.hole) ? 1 : 0);
}

function getTeamBestNet(players, strokeSets, indexes, hole) {
  const nets = indexes
    .map(i => getPlayerNet(players[i], strokeSets[i], hole))
    .filter(v => v !== null);
  return nets.length ? Math.min(...nets) : null;
}

function getTeamCombinedNet(players, strokeSets, indexes, holes) {
  let total = 0;
  let count = 0;
  holes.forEach(h => {
    indexes.forEach(i => {
      const net = getPlayerNet(players[i], strokeSets[i], h);
      if (net !== null) {
        total += net;
        count++;
      }
    });
  });
  return count ? total : null;
}

function countTeamNetBirdies(players, strokeSets, indexes, holes) {
  return holes.reduce((total, h) => {
    const bestNet = getTeamBestNet(players, strokeSets, indexes, h);
    return total + (bestNet !== null && bestNet < h.par ? 1 : 0);
  }, 0);
}

function countTeamGrossPars(players, indexes, holes) {
  return holes.reduce((total, h) => {
    indexes.forEach(i => {
      const gross = getPlayerGross(players[i], h);
      if (gross !== null && gross <= h.par) total++;
    });
    return total;
  }, 0);
}

function calcTieBreakerWinner(players, strokeSets, holes) {
  const t1 = [0, 1];
  const t2 = [2, 3];
  const t1Combined = getTeamCombinedNet(players, strokeSets, t1, holes);
  const t2Combined = getTeamCombinedNet(players, strokeSets, t2, holes);

  if (t1Combined !== null && t2Combined !== null && t1Combined !== t2Combined) {
    return {
      winner: t1Combined < t2Combined ? 0 : 1,
      label: 'TB · Combined Net',
      detail: `Combined Net ${t1Combined}-${t2Combined}`
    };
  }

  const hardest = [...holes].sort((a, b) => a.hcp - b.hcp);
  for (const h of hardest) {
    const t1Best = getTeamBestNet(players, strokeSets, t1, h);
    const t2Best = getTeamBestNet(players, strokeSets, t2, h);
    if (t1Best !== null && t2Best !== null && t1Best !== t2Best) {
      return {
        winner: t1Best < t2Best ? 0 : 1,
        label: 'TB · Hardest Hole',
        detail: `Hardest-hole tiebreaker on hole ${h.hole}`
      };
    }
  }

  const t1Birdies = countTeamNetBirdies(players, strokeSets, t1, holes);
  const t2Birdies = countTeamNetBirdies(players, strokeSets, t2, holes);
  if (t1Birdies !== t2Birdies) {
    return {
      winner: t1Birdies > t2Birdies ? 0 : 1,
      label: 'TB · Net Birdies',
      detail: `Net birdies ${t1Birdies}-${t2Birdies}`
    };
  }

  const t1GrossPars = countTeamGrossPars(players, t1, holes);
  const t2GrossPars = countTeamGrossPars(players, t2, holes);
  if (t1GrossPars !== t2GrossPars) {
    return {
      winner: t1GrossPars > t2GrossPars ? 0 : 1,
      label: 'TB · Gross Pars',
      detail: `Gross pars-or-better ${t1GrossPars}-${t2GrossPars}`
    };
  }

  return { winner: null, label: 'ALL SQUARE', detail: 'No automatic tiebreaker separated the teams.' };
}

// Returns { matchStatus, matchOver, matchResult, winner(index 0=t1,1=t2,null=tie), holesWithScores }
function calcMatchState(players, strokeSets, holes) {
  let matchStatus = 0; // positive = team1 up
  let matchOver = false;
  let matchOverResult = '';
  let holesWithScores = 0;

  for(let hi = 0; hi < holes.length; hi++) {
    if(matchOver) break;
    const h = holes[hi];
    const t1nets = [0,1].map(pi => {
      const key = `${players[pi].id}_${h.hole}`;
      const g = scorecardScores[key] ? parseInt(scorecardScores[key]) : null;
      return g !== null ? g - (strokeSets[pi].has(h.hole) ? 1 : 0) : null;
    }).filter(s => s !== null);
    const t2nets = [2,3].map(pi => {
      const key = `${players[pi].id}_${h.hole}`;
      const g = scorecardScores[key] ? parseInt(scorecardScores[key]) : null;
      return g !== null ? g - (strokeSets[pi].has(h.hole) ? 1 : 0) : null;
    }).filter(s => s !== null);

    // Only score the hole if at least one player from each team has a score
    if(!t1nets.length || !t2nets.length) continue;

    holesWithScores++;
    const t1best = Math.min(...t1nets);
    const t2best = Math.min(...t2nets);
    if(t1best < t2best) matchStatus++;
    else if(t2best < t1best) matchStatus--;

    const holesLeft = holes.length - (hi + 1);
    if(Math.abs(matchStatus) > holesLeft) {
      matchOver = true;
      matchOverResult = `${Math.abs(matchStatus)}&${holesLeft}`;
    }
  }

  let matchResult = '', winner = null;
  if(matchOver) {
    matchResult = matchOverResult;
    winner = matchStatus > 0 ? 0 : 1;
  } else if(holesWithScores === holes.length) {
    // All 9 holes scored
    if(matchStatus === 0) {
      const tb = calcTieBreakerWinner(players, strokeSets, holes);
      matchResult = tb.label;
      winner = tb.winner;
      return {matchStatus, matchOver, matchResult, winner, holesWithScores, tieBreaker: tb};
    }
    else { matchResult = `${Math.abs(matchStatus)} UP`; winner = matchStatus > 0 ? 0 : 1; }
  } else {
    // In progress
    if(matchStatus === 0) matchResult = holesWithScores > 0 ? 'AS (in progress)' : '';
    else matchResult = `${Math.abs(matchStatus)} ${matchStatus > 0 ? 'UP T1' : 'UP T2'} (thru ${holesWithScores})`;
  }

  return {matchStatus, matchOver, matchResult, winner, holesWithScores};
}

function renderScorecard() {
  const holes = getHoles();
  const side = document.getElementById('sc-side').value;
  const players = getPlayers();
  const strokes = calcPlayerStrokes(players, side);
  const strokeSets = players.map((p,i) => getStrokeHoles(strokes[i], holes));

  // Build table
  const totalPar = holes.reduce((s,h)=>s+h.par,0);
  let html = `<thead><tr>
    <th style="text-align:left;padding-left:8px">Player</th>
    <th>Hdcp<br><span style="font-size:9px;color:rgba(107,130,153,0.7)">(9-hole)</span></th>
    ${holes.map(h=>`<th class="h-col">${h.hole}</th>`).join('')}
    <th>NET</th>
  </tr>
  <tr class="par-row">
    <td style="text-align:left;padding-left:8px">Par</td><td></td>
    ${holes.map(h=>`<td>${h.par}</td>`).join('')}
    <td class="tot">${totalPar}</td>
  </tr>
  <tr class="hcp-row">
    <td style="text-align:left;padding-left:8px">HCP</td><td></td>
    ${holes.map(h=>`<td>${h.hcp}</td>`).join('')}
    <td></td>
  </tr></thead><tbody>`;

  players.forEach((p, pi) => {
    const ch = isNaN(parseFloat(p.ghin)) ? null : nineHoleHdcp(p.ghin, side);
    const ns = strokes[pi];
    const rowClass = pi < 2 ? 't1-bg' : 't2-bg';
    const divClass = pi === 2 ? ' team-divider' : '';
    let netTotal = 0;
    let netCount = 0;

    let tds = '';
    holes.forEach(h => {
      const key = `${p.id}_${h.hole}`;
      const hasStroke = strokeSets[pi].has(h.hole);
      const gross = scorecardScores[key] ? parseInt(scorecardScores[key]) : null;
      if(gross !== null) {
        netTotal += gross - (hasStroke ? 1 : 0);
        netCount++;
      }
      tds += `<td>
        <input class="score-inp${hasStroke?' stroke':''}" type="number" min="1" max="15"
          data-key="${key}" value="${scorecardScores[key]||''}"
          oninput="onScoreInput(this)">
        ${hasStroke?'<span class="star">★</span>':''}
      </td>`;
    });

    html += `<tr class="${rowClass}${divClass}">
      <td class="pname-cell">${p.name}</td>
      <td class="hdcp-cell">${ch !== null ? `${ch}${ns>0?` <span style="color:var(--green);font-size:10px">(+${ns})</span>`:''}`:'—'}</td>
      ${tds}
      <td class="net-cell">${netCount>0?netTotal:'—'}</td>
    </tr>`;
  });

  // Match status row — hole by hole
  html += `<tr class="match-row" style="background:rgba(0,0,0,0.25)">
    <td colspan="2" style="text-align:left;padding-left:8px;font-family:'Barlow Condensed',sans-serif;font-size:10px;color:var(--muted);font-weight:700;letter-spacing:1px">MATCH</td>`;

  let runningStatus = 0;
  let runningOver = false;
  holes.forEach((h, hi) => {
    if(runningOver) { html+=`<td></td>`; return; }
    const t1nets = [0,1].map(pi=>{const key=`${players[pi].id}_${h.hole}`;const g=scorecardScores[key]?parseInt(scorecardScores[key]):null;return g!==null?g-(strokeSets[pi].has(h.hole)?1:0):null;}).filter(s=>s!==null);
    const t2nets = [2,3].map(pi=>{const key=`${players[pi].id}_${h.hole}`;const g=scorecardScores[key]?parseInt(scorecardScores[key]):null;return g!==null?g-(strokeSets[pi].has(h.hole)?1:0):null;}).filter(s=>s!==null);
    if(!t1nets.length||!t2nets.length){ html+=`<td class="ev">·</td>`; return; }
    const t1b=Math.min(...t1nets), t2b=Math.min(...t2nets);
    if(t1b<t2b){runningStatus++;html+=`<td class="up">▲</td>`;}
    else if(t2b<t1b){runningStatus--;html+=`<td class="dn">▼</td>`;}
    else{html+=`<td class="ev">–</td>`;}
    const left=holes.length-(hi+1);
    if(Math.abs(runningStatus)>left) runningOver=true;
  });
  html += `<td></td></tr></tbody>`;

  document.getElementById('live-scorecard').innerHTML = html;
  document.getElementById('scorecard-card').style.display = 'block';
  document.getElementById('save-bar').style.display = 'block';

  // Update save bar status
  const state = calcMatchState(players, strokeSets, holes);
  const team1name = document.getElementById('sc-team1').value;
  const team2name = document.getElementById('sc-team2').value;

  document.getElementById('status-display').textContent = state.matchResult || '—';
  if(state.winner === 0) {
    document.getElementById('winner-display').textContent = state.tieBreaker ? `🏆 ${team1name} wins by tiebreaker (${state.tieBreaker.detail})` : `🏆 ${team1name} leads`;
  } else if(state.winner === 1) {
    document.getElementById('winner-display').textContent = state.tieBreaker ? `🏆 ${team2name} wins by tiebreaker (${state.tieBreaker.detail})` : `🏆 ${team2name} leads`;
  } else if(state.holesWithScores > 0 && state.matchResult.includes('ALL SQUARE')) {
    document.getElementById('winner-display').textContent = 'Match tied — review tiebreaker manually before saving';
  } else {
    document.getElementById('winner-display').textContent = state.holesWithScores > 0 ? 'Match in progress' : 'Enter scores to begin';
  }

  // Re-attach listeners to new inputs
  document.querySelectorAll('.score-inp').forEach(inp => {
    inp.addEventListener('input', function() { onScoreInput(this); });
  });
}

function onScoreInput(el) {
  const key = el.dataset.key;
  const val = el.value.trim();
  if(val && parseInt(val) > 0) scorecardScores[key] = val;
  else delete scorecardScores[key];
  renderScorecard();
}

// ── SAVE MATCH ──
function saveMatch() {
  const week = parseInt(document.getElementById('sc-week').value);
  const side = document.getElementById('sc-side').value;
  const sideLabel = side === 'front' ? 'Front 9' : 'Back 9';
  const team1 = document.getElementById('sc-team1').value;
  const team2 = document.getElementById('sc-team2').value;

  if(!week) { alert('Please enter a week number.'); return; }
  if(!team1 || !team2 || team1 === team2) { alert('Please select two different teams.'); return; }

  const holes = getHoles();
  const players = getPlayers();
  const strokes = calcPlayerStrokes(players, side);
  const strokeSets = players.map((p,i) => getStrokeHoles(strokes[i], holes));
  const state = calcMatchState(players, strokeSets, holes);

  if(state.holesWithScores === 0) { alert('Please enter at least some scores before saving.'); return; }
  if(state.holesWithScores < holes.length && !confirm('This match is not fully scored yet. Save the current result anyway?')) return;
  if(state.holesWithScores === holes.length && state.winner === null) {
    alert('This match is still tied after all automatic tiebreakers. Please review manually before saving.');
    return;
  }

  const winnerName = state.winner === 0 ? team1 : state.winner === 1 ? team2 : null;

  // Update records
  const t1 = TEAMS.find(t => t.name === team1);
  const t2 = TEAMS.find(t => t.name === team2);
  if(winnerName === team1) { t1.w++; t2.l++; }
  else if(winnerName === team2) { t2.w++; t1.l++; }
  else { t1.w += 0.5; t2.w += 0.5; } // Halved

  const playerLine = [
    players[0].name + ' & ' + players[1].name,
    'vs',
    players[2].name + ' & ' + players[3].name
  ].join(' ');

  RESULTS.push({
    week, side: sideLabel, team1, team2,
    winner: winnerName,
    matchResult: state.matchResult,
    playerLine,
    holesPlayed: state.holesWithScores,
    playersSnapshot: players.map(p => ({id:p.id, name:p.name, ghin:p.ghin, team:p.team})),
    scoreSnapshot: {...scorecardScores}
  });

  persistState();
  rebuildAll();

  // Reset form
  scorecardScores = {};
  ['p1a','p1b','p2a','p2b'].forEach(id => {
    document.getElementById(id+'-name').value = '';
    document.getElementById(id+'-ghin').value = '';
  });
  document.getElementById('sc-week').value = '';
  document.getElementById('scorecard-card').style.display = 'none';
  document.getElementById('save-bar').style.display = 'none';

  const s = document.getElementById('sc-success');
  s.style.display = 'block';
  setTimeout(() => s.style.display = 'none', 4000);
}

function removeLastResult() {
  if(!RESULTS.length) { alert('No results to remove.'); return; }
  removeResultAt(RESULTS.length - 1);
}

// ── COMMISSIONER LOGIN ──
function doLogin() {
  const name = document.getElementById('login-name').value.trim();
  const pass = document.getElementById('login-pass').value.trim();
  const match = COMMISSIONERS.find(c => c.name.toLowerCase() === name.toLowerCase() && c.password === pass);
  if(match) {
    currentUser = match.name;
    document.getElementById('login-panel').style.display = 'none';
    document.getElementById('commissioner-panel').style.display = 'block';
    document.getElementById('comm-user').textContent = '👋 Welcome, ' + match.name;
    document.getElementById('login-error').style.display = 'none';
    document.getElementById('login-pass').value = '';
    buildEntrySelects();
  } else {
    document.getElementById('login-error').style.display = 'block';
  }
}

function doLogout() {
  currentUser = null;
  document.getElementById('login-panel').style.display = 'block';
  document.getElementById('commissioner-panel').style.display = 'none';
  document.getElementById('login-name').value = '';
  document.getElementById('login-pass').value = '';
}

function buildEntrySelects() {
  const opts = TEAMS.map(t => `<option value="${t.name}">${t.name}</option>`).join('');
  document.getElementById('sc-team1').innerHTML = opts;
  document.getElementById('sc-team2').innerHTML = opts;
  document.getElementById('sc-team1').onchange = renderScorecard;
  document.getElementById('sc-team2').onchange = renderScorecard;
  document.getElementById('sc-team2').selectedIndex = 1;
  buildScheduledMatchSelect();
  buildRosterDatalist();
  buildResultManager();
}

function showCommTab(id, btn) {
  document.querySelectorAll('.comm-tab').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById('scorecard-tab').style.display = id==='scorecard-tab' ? 'block' : 'none';
  document.getElementById('manage-tab').style.display = id==='manage-tab' ? 'block' : 'none';
}

function show(id, btn) {
  document.querySelectorAll('.section').forEach(s => s.classList.remove('active'));
  document.querySelectorAll('.nav-btn').forEach(b => b.classList.remove('active'));
  document.getElementById(id).classList.add('active');
  btn.classList.add('active');
}

function setView(view, btn) {
  document.querySelectorAll('.view-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  document.getElementById('view-table').style.display = view==='table' ? 'block' : 'none';
  document.getElementById('view-cards').style.display = view==='cards' ? 'block' : 'none';
}

// ── STATS ENGINE ──

const AVATAR_COLORS = ['#2ecc40','#1a6fc4','#e63946','#f5c518','#a8d8ea','#9b59b6','#e67e22','#1abc9c','#e91e63','#00bcd4','#ff5722','#8bc34a'];

function getAvatarColor(name) {
  let hash = 0;
  for(let i=0;i<name.length;i++) hash = name.charCodeAt(i) + ((hash<<5)-hash);
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

function normalizePlayerStatName(name) {
  return String(name || '').trim().replace(/\s+/g, ' ');
}

function countScoreSnapshotEntries(snapshot) {
  if (!snapshot || typeof snapshot !== 'object') return 0;
  let count = 0;
  Object.keys(snapshot).forEach(function(key) {
    const val = snapshot[key];
    if (val && typeof val === 'object') {
      Object.keys(val).forEach(function(innerKey) {
        const n = parseInt(val[innerKey], 10);
        if (Number.isFinite(n) && n > 0) count++;
      });
      return;
    }
    const n = parseInt(val, 10);
    if (Number.isFinite(n) && n > 0) count++;
  });
  return count;
}

function getStatsMatchKey(result, index) {
  const week = parseInt(result.week, 10) || 0;
  const side = String(result.side || '').trim().toLowerCase().replace(/\s+/g, ' ');
  const teams = [normalizeTeamName(result.team1), normalizeTeamName(result.team2)]
    .filter(Boolean)
    .sort()
    .join(' vs ');

  // One weekly head-to-head matchup should only count once in player stats.
  // This protects against duplicate saved rows in Google Sheets making players show 2-0 / 0-2 after one week.
  if (week && teams) return `week:${week}|side:${side}|teams:${teams}`;
  return result.resultId ? `id:${result.resultId}` : `row:${index}`;
}

function chooseBetterStatsResult(current, candidate) {
  if (!current) return candidate;
  const currentScores = countScoreSnapshotEntries(current.result.scoreSnapshot);
  const candidateScores = countScoreSnapshotEntries(candidate.result.scoreSnapshot);
  if (candidateScores !== currentScores) return candidateScores > currentScores ? candidate : current;

  const currentPlayers = Array.isArray(current.result.playersSnapshot) ? current.result.playersSnapshot.length : 0;
  const candidatePlayers = Array.isArray(candidate.result.playersSnapshot) ? candidate.result.playersSnapshot.length : 0;
  if (candidatePlayers !== currentPlayers) return candidatePlayers > currentPlayers ? candidate : current;

  const currentHoles = Number(current.result.holesPlayed || 0);
  const candidateHoles = Number(candidate.result.holesPlayed || 0);
  if (candidateHoles !== currentHoles) return candidateHoles > currentHoles ? candidate : current;

  // If they are otherwise the same, use the later row. This makes edited/re-saved rows win.
  return candidate.index >= current.index ? candidate : current;
}

function getUniqueResultsForPlayerStats() {
  const byMatch = new Map();
  RESULTS.forEach(function(result, index) {
    if (!result || !result.week || !result.team1 || !result.team2) return;
    const key = getStatsMatchKey(result, index);
    byMatch.set(key, chooseBetterStatsResult(byMatch.get(key), { result, index }));
  });
  return Array.from(byMatch.values())
    .sort(function(a, b) { return a.index - b.index; })
    .map(function(item) { return item.result; });
}

function parsePlayerLinePlayers(playerLine) {
  const parts = String(playerLine || '').split(/\s+vs\s+/i);
  const t1p = parts[0] ? parts[0].split(/\s*&\s*/).map(normalizePlayerStatName) : ['', ''];
  const t2p = parts[1] ? parts[1].split(/\s*&\s*/).map(normalizePlayerStatName) : ['', ''];
  return [t1p[0] || '', t1p[1] || '', t2p[0] || '', t2p[1] || ''];
}

function getScoreForPlayerHole(scoreSnapshot, player, playerIndex, holeNumber) {
  if (!scoreSnapshot || typeof scoreSnapshot !== 'object') return null;
  const fallbackIds = ['p1a', 'p1b', 'p2a', 'p2b'];
  const candidateIds = [
    player.id,
    player.playerId,
    player.key,
    fallbackIds[playerIndex],
    'p' + (playerIndex + 1),
    String(playerIndex + 1)
  ].filter(Boolean);

  const candidateKeys = [];
  candidateIds.forEach(function(id) {
    candidateKeys.push(id + '_' + holeNumber);
    candidateKeys.push(id + '-' + holeNumber);
    candidateKeys.push(id + '.' + holeNumber);
    candidateKeys.push(id + String(holeNumber));
  });

  for (const key of candidateKeys) {
    if (scoreSnapshot[key] !== undefined && scoreSnapshot[key] !== null && scoreSnapshot[key] !== '') {
      const parsed = parseInt(scoreSnapshot[key], 10);
      return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
    }
  }

  const name = normalizePlayerStatName(player.name);
  if (name && scoreSnapshot[name] && typeof scoreSnapshot[name] === 'object') {
    const nested = scoreSnapshot[name][holeNumber] || scoreSnapshot[name]['Hole ' + holeNumber] || scoreSnapshot[name]['#' + holeNumber];
    const parsed = parseInt(nested, 10);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : null;
  }

  return null;
}

function computePlayerStats() {
  const players = {};
  const statResults = getUniqueResultsForPlayerStats();

  statResults.forEach(function(result) {
    var side = result.side === 'Front 9' ? 'front' : 'back';
    var holes = side === 'front' ? COURSE.front : COURSE.back;
    var allPlayers = [];
    var snap = Array.isArray(result.playersSnapshot) ? result.playersSnapshot : [];

    if (snap.length >= 4) {
      allPlayers = [
        {name:normalizePlayerStatName(snap[0].name || snap[0]['Player Name'] || ''), id:snap[0].id || snap[0].playerId || 'p1a', ghin:snap[0].ghin || snap[0].GHIN || '', team:result.team1, won:result.winner===result.team1, lost:result.winner===result.team2},
        {name:normalizePlayerStatName(snap[1].name || snap[1]['Player Name'] || ''), id:snap[1].id || snap[1].playerId || 'p1b', ghin:snap[1].ghin || snap[1].GHIN || '', team:result.team1, won:result.winner===result.team1, lost:result.winner===result.team2},
        {name:normalizePlayerStatName(snap[2].name || snap[2]['Player Name'] || ''), id:snap[2].id || snap[2].playerId || 'p2a', ghin:snap[2].ghin || snap[2].GHIN || '', team:result.team2, won:result.winner===result.team2, lost:result.winner===result.team1},
        {name:normalizePlayerStatName(snap[3].name || snap[3]['Player Name'] || ''), id:snap[3].id || snap[3].playerId || 'p2b', ghin:snap[3].ghin || snap[3].GHIN || '', team:result.team2, won:result.winner===result.team2, lost:result.winner===result.team1},
      ];
    } else {
      var parsedNames = parsePlayerLinePlayers(result.playerLine);
      allPlayers = [
        {name:parsedNames[0], id:'p1a', team:result.team1, won:result.winner===result.team1, lost:result.winner===result.team2},
        {name:parsedNames[1], id:'p1b', team:result.team1, won:result.winner===result.team1, lost:result.winner===result.team2},
        {name:parsedNames[2], id:'p2a', team:result.team2, won:result.winner===result.team2, lost:result.winner===result.team1},
        {name:parsedNames[3], id:'p2b', team:result.team2, won:result.winner===result.team2, lost:result.winner===result.team1},
      ];
    }

    allPlayers.forEach(function(p, playerIndex) {
      if(!p.name || /^Player\s/i.test(p.name)) return;
      if(!players[p.name]) {
        players[p.name] = {name:p.name, team:p.team, matchWins:0, matchLosses:0, matchTies:0,
          roundsPlayed:0, totalGross:0, totalHoles:0, bestGross:Infinity, worstGross:-Infinity,
          parDiffs:[], birdies:0, pars:0, bogeys:0, doubles:0, worse:0, holeScores:{}};
      }
      var ps = players[p.name];
      ps.team = p.team;

      // Count the team match result once per player per unique match.
      if(p.won) ps.matchWins++;
      else if(p.lost) ps.matchLosses++;
      else ps.matchTies++;

      var scoreSnapshot = result.scoreSnapshot || {};
      // Full individual course handicap for stats (not relative to lowest)
      var fullHdcp = (p.ghin && p.ghin !== '') ? nineHoleHdcp(p.ghin, side) : null;
      var fullStrokeHoles = fullHdcp !== null ? getStrokeHoles(fullHdcp, holes) : new Set();
      var grossTotal=0, holeCount=0;
      holes.forEach(function(h) {
        var gross = getScoreForPlayerHole(scoreSnapshot, p, playerIndex, h.hole);
        if(gross===null || isNaN(gross)) return;
        holeCount++;
        grossTotal += gross;
        ps.totalGross += gross;
        ps.totalHoles++;
        // Net score uses full individual handicap
        var net = fullHdcp !== null && fullHdcp < 0 ? gross : gross - (fullStrokeHoles.has(h.hole) ? 1 : 0);
        ps.totalNet = (ps.totalNet || 0) + net;
        ps.parDiffs.push(gross - h.par);
        var diff = gross - h.par;
        var netDiff = net - h.par;
        if(diff <= -1) ps.birdies++;
        else if(diff===0) ps.pars++;
        else if(diff===1) ps.bogeys++;
        else if(diff===2) ps.doubles++;
        else ps.worse++;
        if(netDiff <= -1) ps.netBirdies = (ps.netBirdies || 0) + 1;
        if(!ps.holeScores[h.hole]) ps.holeScores[h.hole] = [];
        ps.holeScores[h.hole].push({gross:gross, par:h.par});
      });
      if(holeCount > 0) {
        ps.roundsPlayed++;
        if(grossTotal < ps.bestGross) ps.bestGross = grossTotal;
        if(grossTotal > ps.worstGross) ps.worstGross = grossTotal;
        // Best/worst net round — sum net scores hole-by-hole (same strokes as totalNet)
        var roundNet = 0;
        holes.forEach(function(h) {
          var key = p.id + '_' + h.hole;
          var raw = scoreSnapshot[key];
          var g = (raw !== undefined && raw !== null && raw !== '') ? parseInt(raw) : null;
          if(g === null || isNaN(g)) return;
          roundNet += g - (fullStrokeHoles.has(h.hole) ? 1 : 0);
        });
        if(ps.bestNet === undefined || roundNet < ps.bestNet) ps.bestNet = roundNet;
        if(ps.worstNet === undefined || roundNet > ps.worstNet) ps.worstNet = roundNet;
      }
    });
  });
  return players;
}


let currentStatFilter = 'all';

function setStatFilter(f, btn) {
  currentStatFilter = f;
  document.querySelectorAll('.stats-filter-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  buildStats();
}

function filterPlayerStats() {
  const q = document.getElementById('player-search').value.toLowerCase();
  document.querySelectorAll('.player-stat-card').forEach(card => {
    card.style.display = card.dataset.player.toLowerCase().includes(q) ? 'block' : 'none';
  });
}

function buildStats() {
  const players = computePlayerStats();
  const playerList = Object.values(players);
  const noData = document.getElementById('stats-no-data');
  const container = document.getElementById('stats-container');

  if(!playerList.length) {
    noData.style.display = 'flex';
    container.style.display = 'none';
    return;
  }
  noData.style.display = 'none';
  container.style.display = 'block';

  // Leaders
  const withScores = playerList.filter(p=>p.totalHoles>0);
  const withRounds = playerList.filter(p=>p.roundsPlayed>0);
  const bestAvg = withScores.length ? withScores.reduce((b,p)=>(p.totalGross/p.totalHoles)<(b.totalGross/b.totalHoles)?p:b) : null;
  const mostWins = playerList.length ? playerList.reduce((b,p)=>p.matchWins>b.matchWins?p:b) : null;
  const bestRound = withRounds.length ? withRounds.reduce((b,p)=>p.bestGross<b.bestGross?p:b) : null;

  document.getElementById('leaders-row').innerHTML =
    '<div class="leader-card gold">' +
      '<div class="leader-icon">🏆</div>' +
      '<div class="leader-stat">' + (mostWins&&mostWins.matchWins>0?mostWins.matchWins:'—') + '</div>' +
      '<div class="leader-name">' + (mostWins&&mostWins.matchWins>0?mostWins.name:'TBD') + '</div>' +
      '<div class="leader-label">Most Match Wins</div>' +
    '</div>' +
    '<div class="leader-card green">' +
      '<div class="leader-icon">🎯</div>' +
      '<div class="leader-stat">' + (bestAvg?(bestAvg.totalGross/bestAvg.totalHoles).toFixed(1):'—') + '</div>' +
      '<div class="leader-name">' + (bestAvg?bestAvg.name:'TBD') + '</div>' +
      '<div class="leader-label">Best Avg / Hole</div>' +
    '</div>' +
    '<div class="leader-card ice">' +
      '<div class="leader-icon">⭐</div>' +
      '<div class="leader-stat">' + (bestRound&&bestRound.bestGross!==Infinity?bestRound.bestGross:'—') + '</div>' +
      '<div class="leader-name">' + (bestRound&&bestRound.bestGross!==Infinity?bestRound.name:'TBD') + '</div>' +
      '<div class="leader-label">Best Round</div>' +
    '</div>';

  // Filter & sort
  let filtered = currentStatFilter === 'leaders'
    ? playerList.filter(p=>p.matchWins>0).sort((a,b)=>b.matchWins-a.matchWins)
    : playerList.sort((a,b)=>a.name.localeCompare(b.name));

  document.getElementById('player-search-wrap').style.display =
    currentStatFilter==='all' && filtered.length>4 ? 'block' : 'none';

  // Player cards
  const cards = filtered.map(p => {
    const avgGross = p.totalHoles>0 ? (p.totalGross/p.totalHoles).toFixed(2) : '—';
    const sumDiff = p.parDiffs.reduce((s,v)=>s+v,0);
    const avgVsPar = p.parDiffs.length>0 ? (sumDiff/p.parDiffs.length).toFixed(2) : '—';
    const totalMatches = p.matchWins+p.matchLosses+p.matchTies;
    const winPct = totalMatches>0 ? Math.round(p.matchWins/totalMatches*100) : 0;
    const recordClass = p.matchWins>p.matchLosses?'':p.matchLosses>p.matchWins?' losing':' even';
    const avatarColor = getAvatarColor(p.name);
    const initials = p.name.split(' ').map(w=>w[0]).join('').slice(0,2).toUpperCase();
    const bestG = p.bestGross!==Infinity?p.bestGross:'—';
    const worstG = p.worstGross!==-Infinity?p.worstGross:'—';
    const bestN = (p.bestNet !== undefined && p.bestNet !== Infinity) ? p.bestNet : '—';
    const worstN = (p.worstNet !== undefined && p.worstNet !== -Infinity) ? p.worstNet : '—';
    const maxBar = Math.max(p.birdies,p.pars,p.bogeys,p.doubles,p.worse,1);
    const cardId = 'psc_' + p.name.replace(/[^a-zA-Z0-9]/g,'_');
    const avgVsParNum = parseFloat(avgVsPar);
    const avgVsParColor = isNaN(avgVsParNum)?'var(--muted)':avgVsParNum>0?'var(--red)':'var(--green)';
    const avgVsParStr = avgVsPar==='—'?'—':(avgVsParNum>0?'+':'')+avgVsPar;

    const bars = [
      {label:'🦅',cls:'birdie',val:p.birdies},
      {label:'Par',cls:'par',val:p.pars},
      {label:'+1',cls:'bogey',val:p.bogeys},
      {label:'+2',cls:'double',val:p.doubles},
      {label:'+3',cls:'worse',val:p.worse},
    ];
    const distHtml = p.totalHoles>0 ? (
      '<div class="score-dist-wrap">' +
      '<div class="score-dist-title">Score Distribution</div>' +
      '<div class="score-dist">' +
      bars.map(b =>
        '<div class="score-bar-wrap">' +
        '<div class="score-bar-count">' + b.val + '</div>' +
        '<div class="score-bar ' + b.cls + '" style="height:' + Math.max(4,Math.round(b.val/maxBar*36)) + 'px"></div>' +
        '<div class="score-bar-label">' + b.label + '</div>' +
        '</div>'
      ).join('') +
      '</div></div>'
    ) : '';

    return '<div class="player-stat-card" data-player="' + p.name + '">' +
      '<div class="psc-header" onclick="togglePlayerDetail(\'' + cardId + '\')">' +
        '<div class="psc-avatar" style="background:' + avatarColor + '">' + initials + '</div>' +
        '<div class="psc-info">' +
          '<div class="psc-name">' + p.name + '</div>' +
          '<div class="psc-team">' + p.team + '</div>' +
        '</div>' +
        '<div class="psc-record' + recordClass + '">' + p.matchWins + '-' + p.matchLosses + (p.matchTies>0?'-'+p.matchTies:'') + '</div>' +
        '<div class="psc-chevron" id="chev_' + cardId + '">▼</div>' +
      '</div>' +
      '<div class="psc-stats-grid">' +
        '<div class="psc-stat"><div class="psc-stat-num">' + winPct + '%</div><div class="psc-stat-label">Win %</div></div>' +
        '<div class="psc-stat"><div class="psc-stat-num">' + avgGross + '</div><div class="psc-stat-label">Avg/Hole</div></div>' +
        '<div class="psc-stat"><div class="psc-stat-num" style="color:var(--gold)">' + bestG + '</div><div class="psc-stat-label">Best Gross</div></div>' +
        '<div class="psc-stat"><div class="psc-stat-num" style="color:' + avgVsParColor + '">' + avgVsParStr + '</div><div class="psc-stat-label">Avg vs Par</div></div>' +
      '</div>' +
      '<div class="psc-detail" id="' + cardId + '">' +
        '<div class="psc-detail-grid">' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Rounds</span><span class="psc-detail-val">' + p.roundsPlayed + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Holes Played</span><span class="psc-detail-val">' + p.totalHoles + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Best Gross</span><span class="psc-detail-val" style="color:var(--gold)">' + bestG + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Worst Gross</span><span class="psc-detail-val" style="color:var(--red)">' + worstG + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Best Net</span><span class="psc-detail-val" style="color:var(--green)">' + bestN + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Worst Net</span><span class="psc-detail-val">' + worstN + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Birdies/Eagles</span><span class="psc-detail-val" style="color:var(--gold)">' + p.birdies + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Pars</span><span class="psc-detail-val" style="color:var(--green)">' + p.pars + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Bogeys</span><span class="psc-detail-val">' + p.bogeys + '</span></div>' +
          '<div class="psc-detail-item"><span class="psc-detail-label">Double+</span><span class="psc-detail-val" style="color:var(--red)">' + (p.doubles+p.worse) + '</span></div>' +
        '</div>' +
        distHtml +
      '</div>' +
    '</div>';
  });

  document.getElementById('player-cards-container').innerHTML = cards.join('');
  buildHoleBreakdown(players);
}

function togglePlayerDetail(id) {
  const el = document.getElementById(id);
  const chev = document.getElementById('chev_' + id);
  if(!el) return;
  el.classList.toggle('open');
  if(chev) chev.classList.toggle('open');
}

function buildHoleBreakdown(players) {
  const playerList = Object.values(players).filter(p=>p.totalHoles>0);
  const container = document.getElementById('hole-breakdown-container');
  if(!playerList.length) { container.innerHTML=''; return; }

  const allHoleNums = new Set();
  playerList.forEach(p=>Object.keys(p.holeScores).forEach(h=>allHoleNums.add(parseInt(h))));
  const sortedHoles = [...allHoleNums].sort((a,b)=>a-b);

  const parMap = {};
  [...COURSE.front,...COURSE.back].forEach(h=>parMap[h.hole]=h.par);

  let html = '<div class="hole-bdown-wrap"><table class="hole-bdown-table"><thead><tr>' +
    '<th style="text-align:left;padding-left:8px">Player</th>' +
    sortedHoles.map(h=>'<th>#'+h+'</th>').join('') +
    '<th>Avg</th></tr>' +
    '<tr><td class="par-lbl">Par</td>' +
    sortedHoles.map(h=>'<td style="color:var(--muted);font-size:10px">'+(parMap[h]||'')+'</td>').join('') +
    '<td></td></tr></thead><tbody>';

  playerList.sort((a,b)=>a.name.localeCompare(b.name)).forEach(p => {
    const overallAvg = p.totalHoles>0?(p.totalGross/p.totalHoles).toFixed(1):'—';
    html += '<tr><td style="text-align:left;padding-left:8px;font-family:\'Barlow Condensed\',sans-serif;font-weight:700;font-size:11px;color:var(--text);white-space:nowrap">' + p.name + '</td>';
    sortedHoles.forEach(h => {
      const hs = p.holeScores[h];
      if(!hs||!hs.length) { html+='<td style="color:var(--muted)">—</td>'; return; }
      const avg = hs.reduce((s,x)=>s+x.gross,0)/hs.length;
      const par = parMap[h]||4;
      const diff = avg-par;
      const cls = diff<=-0.5?'hcell-under':diff<0.5?'hcell-par':diff<1.5?'hcell-over1':diff<2.5?'hcell-over2':'hcell-over3';
      html += '<td class="'+cls+'" title="'+hs.length+' round'+(hs.length>1?'s':'')+'">'+avg.toFixed(1)+'</td>';
    });
    html += '<td style="font-family:\'Bebas Neue\',sans-serif;font-size:14px;color:var(--ice)">'+overallAvg+'</td></tr>';
  });

  html += '</tbody></table></div><p style="font-family:\'Barlow Condensed\',sans-serif;font-size:10px;color:var(--muted);letter-spacing:1px;text-align:center;margin-top:6px;">🟡 Under par &nbsp;|&nbsp; 🟢 Par &nbsp;|&nbsp; Gray +1 &nbsp;|&nbsp; 🔴 +2 &nbsp;|&nbsp; Darker red +3+</p>';
  container.innerHTML = html;
}

initLeagueSite();

// ── HOLE-BY-HOLE SCORECARD DROPDOWN ──────────────────────────────────────────

function toggleScorecard(btn, resultId) {
  var row = document.getElementById('sc-' + resultId);
  if (!row) return;
  var isOpen = row.style.display !== 'none';
  row.style.display = isOpen ? 'none' : 'block';
  btn.textContent = isOpen ? '▼ View Scorecard' : '▲ Hide Scorecard';
}

function buildScorecardHTML(r) {
  var snap = r.playersSnapshot || [];
  if (!Array.isArray(snap) || snap.length < 4) {
    const parsedNames = parsePlayerLinePlayers(r.playerLine);
    snap = parsedNames.map(function(name, i) {
      return normalizeSnapshotPlayer({ id:['p1a','p1b','p2a','p2b'][i], name:name || ('Player ' + (i + 1)), team:i < 2 ? r.team1 : r.team2 }, i, { Team1:r.team1, Team2:r.team2 });
    });
  }
  var scores = r.scoreSnapshot || {};
  if (!Object.keys(scores).length) {
    return '<div style="padding:10px;color:var(--muted);font-size:12px;text-align:center;">No hole-by-hole data saved for this match.</div>';
  }

  var side = r.side === 'Front 9' ? 'front' : 'back';
  var holes = side === 'front' ? COURSE.front : COURSE.back;

  // Calculate strokes for each player
  var strokes = calcPlayerStrokes(snap, side);
  var strokeSets = snap.map(function(p, i) { return getStrokeHoles(strokes[i], holes); });

  // Cell color by score vs par
  function scoreColor(gross, par) {
    if (gross === null) return '';
    var d = gross - par;
    if (d <= -1) return 'background:#8a6a00;color:#ffe98a;'; // birdie - gold
    if (d === 0)  return 'background:#1a4a2a;color:#7cc77a;'; // par - green
    if (d === 1)  return 'background:#2a2a2a;color:#c0c8d4;'; // bogey - gray
    if (d === 2)  return 'background:#4a1a1a;color:#d66060;'; // double - red
    return 'background:#6a0a0a;color:#ff9999;';               // triple+ - dark red
  }

  // Best ball net per hole per team
  function teamNetBest(playerIdxs, hole) {
    var nets = playerIdxs.map(function(pi) {
      var g = getScoreForPlayerHole(scores, snap[pi], pi, hole.hole);
      if (g === null || isNaN(g)) return null;
      return g - (strokeSets[pi].has(hole.hole) ? 1 : 0);
    }).filter(function(n) { return n !== null; });
    return nets.length ? Math.min.apply(null, nets) : null;
  }

  var cellStyle = 'style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:12px;min-width:28px;"';
  var hdrStyle  = 'style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:10px;letter-spacing:1px;color:var(--muted);font-family:\'Barlow Condensed\',sans-serif;font-weight:700;"';
  var lblStyle  = 'style="border:1px solid rgba(255,255,255,0.1);padding:5px 8px;text-align:left;font-size:11px;font-family:\'Barlow Condensed\',sans-serif;font-weight:700;letter-spacing:.5px;white-space:nowrap;color:var(--muted);"';
  var namStyle  = 'style="border:1px solid rgba(255,255,255,0.1);padding:5px 8px;text-align:left;font-size:12px;font-family:\'Inter Tight\',sans-serif;font-weight:700;white-space:nowrap;color:#f0f4f8;"';

  var html = '<div style="overflow-x:auto;-webkit-overflow-scrolling:touch;">';
  html += '<table style="border-collapse:collapse;width:100%;min-width:520px;font-family:\'Inter Tight\',sans-serif;">';

  // Header row — hole numbers
  html += '<tr>';
  html += '<th ' + hdrStyle + '>PLAYER</th>';
  holes.forEach(function(h) {
    html += '<th ' + hdrStyle + '>' + h.hole + '</th>';
  });
  html += '<th ' + hdrStyle + '>TOT</th>';
  html += '</tr>';

  // Par row
  html += '<tr>';
  html += '<td ' + lblStyle + '>Par</td>';
  var totalPar = 0;
  holes.forEach(function(h) {
    totalPar += h.par;
    html += '<td ' + cellStyle + ' style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:12px;color:var(--muted);">' + h.par + '</td>';
  });
  html += '<td ' + cellStyle + ' style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:12px;color:var(--muted);">' + totalPar + '</td>';
  html += '</tr>';

  // Stroke indicators row
  html += '<tr>';
  html += '<td ' + lblStyle + ' style="border:1px solid rgba(255,255,255,0.1);padding:5px 8px;text-align:left;font-size:10px;font-family:\'Barlow Condensed\',sans-serif;color:var(--muted);">Handicap</td>';
  holes.forEach(function(h) {
    html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:10px;color:var(--muted);">' + h.hcp + '</td>';
  });
  html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;"></td></tr>';

  // Each player's gross row
  snap.forEach(function(p, pi) {
    var teamColor = pi < 2 ? 'rgba(0,84,164,0.25)' : 'rgba(215,25,32,0.2)';
    var grossTotal = 0; var hasAny = false;
    var cells = holes.map(function(h) {
      var g = getScoreForPlayerHole(scores, p, pi, h.hole);
      if (g !== null && !isNaN(g)) { grossTotal += g; hasAny = true; }
      var hasStroke = strokeSets[pi].has(h.hole);
      var sc = scoreColor(g, h.par);
      var dot = hasStroke ? '<span style="color:var(--gold);font-size:8px;vertical-align:super;">●</span>' : '';
      return '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:13px;font-weight:600;' + sc + '">' + (g !== null && !isNaN(g) ? g : '—') + dot + '</td>';
    });
    html += '<tr style="background:' + teamColor + ';">';
    html += '<td ' + namStyle + ' style="border:1px solid rgba(255,255,255,0.1);padding:5px 8px;text-align:left;font-size:12px;font-family:\'Inter Tight\',sans-serif;font-weight:700;white-space:nowrap;color:#f0f4f8;background:' + teamColor + ';">' + p.name + ' <span style="font-size:10px;color:var(--muted);font-weight:400;">(GHIN ' + (p.ghin||'—') + ')</span></td>';
    html += cells.join('');
    html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:13px;font-weight:700;color:#f0f4f8;">' + (hasAny ? grossTotal : '—') + '</td>';
    html += '</tr>';

    // Net row for this player
    var netTotal = 0; var hasNet = false;
    var netCells = holes.map(function(h) {
      var g = getScoreForPlayerHole(scores, p, pi, h.hole);
      if (g === null || isNaN(g)) return '<td style="border:1px solid rgba(255,255,255,0.1);padding:3px;text-align:center;font-size:11px;color:var(--muted);">—</td>';
      var net = g - (strokeSets[pi].has(h.hole) ? 1 : 0);
      netTotal += net; hasNet = true;
      var sc = scoreColor(net, h.par);
      return '<td style="border:1px solid rgba(255,255,255,0.1);padding:3px;text-align:center;font-size:11px;' + sc + '">' + net + '</td>';
    });
    html += '<tr style="background:' + teamColor + ';opacity:0.75;">';
    html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:3px 8px;text-align:left;font-size:10px;font-family:\'Barlow Condensed\',sans-serif;color:var(--muted);letter-spacing:.5px;">NET · ' + p.name + '</td>';
    html += netCells.join('');
    html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:3px;text-align:center;font-size:11px;font-weight:600;color:var(--muted);">' + (hasNet ? netTotal : '—') + '</td>';
    html += '</tr>';
  });

  // Best ball net row per team
  [[0,1],[2,3]].forEach(function(idxs, ti) {
    var teamName = ti === 0 ? r.team1 : r.team2;
    var teamColor = ti === 0 ? 'rgba(0,84,164,0.4)' : 'rgba(215,25,32,0.35)';
    var bbTotal = 0; var bbHoles = 0;
    var bbCells = holes.map(function(h) {
      var best = teamNetBest(idxs, h);
      if (best !== null) { bbTotal += best; bbHoles++; }
      var sc = best !== null ? scoreColor(best, h.par) : '';
      return '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:12px;font-weight:700;' + sc + '">' + (best !== null ? best : '—') + '</td>';
    });
    html += '<tr style="background:' + teamColor + ';">';
    html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 8px;text-align:left;font-size:11px;font-family:\'Barlow Condensed\',sans-serif;font-weight:800;letter-spacing:1px;color:#f0f4f8;white-space:nowrap;">BEST BALL · ' + teamName + '</td>';
    html += bbCells.join('');
    html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:12px;font-weight:800;color:#f0f4f8;">' + (bbHoles ? bbTotal : '—') + '</td>';
    html += '</tr>';
  });

  // Hole winner row
  html += '<tr>';
  html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 8px;text-align:left;font-size:10px;font-family:\'Barlow Condensed\',sans-serif;font-weight:800;letter-spacing:1px;color:var(--gold);">HOLE WINNER</td>';
  var runningStatus = 0;
  holes.forEach(function(h) {
    var t1best = teamNetBest([0,1], h);
    var t2best = teamNetBest([2,3], h);
    var txt, color;
    if (t1best === null && t2best === null) { txt = '—'; color = 'color:var(--muted)'; }
    else if (t1best === null) { txt = '▼'; color = 'color:var(--red,#d66060)'; runningStatus--; }
    else if (t2best === null) { txt = '▲'; color = 'color:var(--green,#7cc77a)'; runningStatus++; }
    else if (t1best < t2best) { txt = '▲'; color = 'color:var(--green,#7cc77a)'; runningStatus++; }
    else if (t2best < t1best) { txt = '▼'; color = 'color:var(--red,#d66060)'; runningStatus--; }
    else { txt = 'AS'; color = 'color:var(--muted)'; }
    html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:11px;font-weight:700;' + color + ';">' + txt + '</td>';
  });
  html += '<td style="border:1px solid rgba(255,255,255,0.1);padding:5px 3px;text-align:center;font-size:11px;font-weight:800;color:var(--gold);">' + r.matchResult + '</td>';
  html += '</tr>';

  html += '</table></div>';

  // Legend
  html += '<div style="display:flex;gap:10px;flex-wrap:wrap;margin-top:8px;padding:0 2px;">';
  [['🟡','Birdie'],['🟢','Par'],['⬜','Bogey'],['🔴','Double'],['⬛','+3 or worse']].forEach(function(item){
    html += '<span style="font-size:10px;color:var(--muted);font-family:\'Barlow Condensed\',sans-serif;letter-spacing:.5px;">' + item[0] + ' ' + item[1] + '</span>';
  });
  html += '<span style="font-size:10px;color:var(--gold);font-family:\'Barlow Condensed\',sans-serif;">● Stroke hole</span>';
  html += '</div>';

  return html;
}

// ── SKINS & CTP ──────────────────────────────────────────────────────────────

var SKINS_DATA = [];
var CTP_DATA = [];

function applySkinsCtpFromSheet(data) {
  SKINS_DATA = (data.skins || []).filter(function(r) {
    return r.Week && r.Player;
  });
  CTP_DATA = (data.ctp || []).filter(function(r) {
    return r.Week && r.Player;
  });
}

function buildExtras() {
  var container = document.getElementById('extras-container');
  if (!container) return;

  var hasSkins = SKINS_DATA.length > 0;
  var hasCTP = CTP_DATA.length > 0;

  if (!hasSkins && !hasCTP) {
    container.innerHTML = '<div class="no-results"><div class="no-results-icon">\ud83c\udfc6</div><div class="no-results-text">No skins or CTP results yet<br>Check back after Week 1</div></div>';
    return;
  }

  var html = '';

  // ── SKINS ────────────────────────────────────────────────────────────────
  if (hasSkins) {
    // Season leaderboard
    var skinsByPlayer = {};
    SKINS_DATA.forEach(function(r) {
      var name = String(r.Player || '').trim();
      if (!name) return;
      if (!skinsByPlayer[name]) skinsByPlayer[name] = { name: name, skins: 0, payout: 0 };
      skinsByPlayer[name].skins += Number(r.Skins || r['# Skins'] || 1);
      skinsByPlayer[name].payout += Number(String(r.Payout || r['Payout ($)'] || 0).replace(/[$,]/g, ''));
    });
    var skinsLeaders = Object.values(skinsByPlayer).sort(function(a, b) {
      return b.payout !== a.payout ? b.payout - a.payout : b.skins - a.skins;
    });

    html += '<div class="section-header" style="margin-top:0"><span class="section-label" style="font-size:18px">Net Skins</span><div class="section-header-line"></div></div>';

    // Leaderboard table
    html += '<div class="extras-card" style="margin-bottom:16px;">';
    html += '<div class="extras-card-title">Season Leaderboard</div>';
    html += '<table class="extras-table"><thead><tr><th>#</th><th style="text-align:left">Player</th><th>Skins</th><th>Payout</th></tr></thead><tbody>';
    skinsLeaders.forEach(function(p, i) {
      html += '<tr class="' + (i===0?'extras-leader':'') + '">' +
        '<td style="color:var(--muted);font-size:12px;">' + (i+1) + '</td>' +
        '<td style="text-align:left;font-weight:700;color:#f0f4f8;">' + p.name + '</td>' +
        '<td style="color:var(--ice);font-family:\'Bebas Neue\',sans-serif;font-size:22px;">' + p.skins + '</td>' +
        '<td style="color:var(--green);font-weight:700;">$' + p.payout.toFixed(2) + '</td>' +
        '</tr>';
    });
    html += '</tbody></table></div>';

    // Week by week results
    var skinsByWeek = {};
    SKINS_DATA.forEach(function(r) {
      var w = String(r.Week || '');
      if (!skinsByWeek[w]) skinsByWeek[w] = [];
      skinsByWeek[w].push(r);
    });
    var sortedSkinsWeeks = Object.keys(skinsByWeek).sort(function(a,b){ return b-a; });

    html += '<div class="extras-card">';
    html += '<div class="extras-card-title">Week by Week</div>';
    sortedSkinsWeeks.forEach(function(week) {
      var rows = skinsByWeek[week];
      var weekPot = rows.reduce(function(s,r){ return s + Number(String(r['Total Pot'] || r.TotalPot || r.Pot || 0).replace(/[$,]/g,'')); }, 0);
      html += '<div class="extras-week-label">Week ' + week + (weekPot ? ' &nbsp;&middot;&nbsp; Pot: $' + weekPot.toFixed(2) : '') + '</div>';
      html += '<table class="extras-table" style="margin-bottom:12px;"><thead><tr><th style="text-align:left">Player</th><th>Hole</th><th>Skins</th><th>Payout</th></tr></thead><tbody>';
      rows.forEach(function(r) {
        var payout = Number(String(r.Payout || r['Payout ($)'] || 0).replace(/[$,]/g,''));
        var skins = Number(r.Skins || r['# Skins'] || 1);
        html += '<tr>' +
          '<td style="text-align:left;font-weight:700;color:#f0f4f8;">' + (r.Player||'') + '</td>' +
          '<td style="color:var(--gold);">' + (r.Hole || r['Hole(s)'] || '—') + '</td>' +
          '<td style="color:var(--ice);font-family:\'Bebas Neue\',sans-serif;font-size:20px;">' + skins + '</td>' +
          '<td style="color:var(--green);font-weight:700;">$' + payout.toFixed(2) + '</td>' +
          '</tr>';
      });
      html += '</tbody></table>';
    });
    html += '</div>';
  }

  // ── CLOSEST TO THE PIN ────────────────────────────────────────────────────
  if (hasCTP) {
    var ctpByPlayer = {};
    CTP_DATA.forEach(function(r) {
      var name = String(r.Player || '').trim();
      if (!name) return;
      if (!ctpByPlayer[name]) ctpByPlayer[name] = { name: name, wins: 0, payout: 0 };
      ctpByPlayer[name].wins++;
      ctpByPlayer[name].payout += Number(String(r.Payout || r['Payout ($)'] || 0).replace(/[$,]/g,''));
    });
    var ctpLeaders = Object.values(ctpByPlayer).sort(function(a,b) {
      return b.wins !== a.wins ? b.wins - a.wins : b.payout - a.payout;
    });

    html += '<div class="section-header" style="margin-top:20px"><span class="section-label" style="font-size:18px">Closest to the Pin</span><div class="section-header-line"></div></div>';

    // CTP Leaderboard
    html += '<div class="extras-card" style="margin-bottom:16px;">';
    html += '<div class="extras-card-title">Season Leaderboard</div>';
    html += '<table class="extras-table"><thead><tr><th>#</th><th style="text-align:left">Player</th><th>Wins</th><th>Payout</th></tr></thead><tbody>';
    ctpLeaders.forEach(function(p, i) {
      html += '<tr class="' + (i===0?'extras-leader':'') + '">' +
        '<td style="color:var(--muted);font-size:12px;">' + (i+1) + '</td>' +
        '<td style="text-align:left;font-weight:700;color:#f0f4f8;">' + p.name + '</td>' +
        '<td style="color:var(--ice);font-family:\'Bebas Neue\',sans-serif;font-size:22px;">' + p.wins + '</td>' +
        '<td style="color:var(--green);font-weight:700;">$' + p.payout.toFixed(2) + '</td>' +
        '</tr>';
    });
    html += '</tbody></table></div>';

    // CTP week by week
    var ctpByWeek = {};
    CTP_DATA.forEach(function(r) {
      var w = String(r.Week || '');
      if (!ctpByWeek[w]) ctpByWeek[w] = [];
      ctpByWeek[w].push(r);
    });
    var sortedCtpWeeks = Object.keys(ctpByWeek).sort(function(a,b){ return b-a; });

    html += '<div class="extras-card">';
    html += '<div class="extras-card-title">Week by Week</div>';
    sortedCtpWeeks.forEach(function(week) {
      var rows = ctpByWeek[week];
      html += '<div class="extras-week-label">Week ' + week + '</div>';
      html += '<table class="extras-table" style="margin-bottom:12px;"><thead><tr><th style="text-align:left">Player</th><th>Hole</th><th>Distance</th><th>Payout</th></tr></thead><tbody>';
      rows.forEach(function(r) {
        var payout = Number(String(r.Payout || r['Payout ($)'] || 0).replace(/[$,]/g,''));
        html += '<tr>' +
          '<td style="text-align:left;font-weight:700;color:#f0f4f8;">' + (r.Player||'') + '</td>' +
          '<td style="color:var(--gold);">Hole ' + (r.Hole||'—') + '</td>' +
          '<td style="color:var(--ice);font-weight:700;">' + (r.Distance || r['Distance (ft/in)'] || '—') + '</td>' +
          '<td style="color:var(--green);font-weight:700;">$' + payout.toFixed(2) + '</td>' +
          '</tr>';
      });
      html += '</tbody></table>';
    });
    html += '</div>';
  }

  container.innerHTML = html;
}
